      this.SetLabelState(TacticalMapControl.LabelMode.None);
  }

  private void CycleLabelTypes()
  {
    switch (this._currentLabelState)
    {
      case TacticalMapControl.LabelMode.None:
        this.SetLabelState(TacticalMapControl.LabelMode.Tactical);
        break;
      case TacticalMapControl.LabelMode.Tactical:
        this.SetLabelState(TacticalMapControl.LabelMode.Area);
        break;
      case TacticalMapControl.LabelMode.Area:
        this.SetLabelState(TacticalMapControl.LabelMode.Tactical);
        break;
    }
  }

  private void ToggleSettingsVisibility()
  {
    this._settingsVisible = !this._settingsVisible;
    this.UpdateSettingsVisibility();
  }

  private void ToggleFollowPlayer()
  {
    this._followingPlayer = !this._followingPlayer;
    this.UpdateFollowButtonText();
    if (!this._followingPlayer)
      return;
    this.CenterOnPlayer();
  }

  private void ResetView()
  {
    this.Map.ResetZoomAndPan();
    this.Canvas.ResetZoomAndPan();
    this._currentZoomFactor = 1f;
    this._currentPanOffset = Vector2.Zero;
    if (!this._followingPlayer)
      return;
    this._followingPlayer = false;
    this.UpdateFollowButtonText();
    this.InvalidatePlayerCache();
  }

  private void CenterOnPlayer()
  {
    Vector2i playerIndices;
    if (!this.TryFindPlayerBlip(out playerIndices))
      return;
    this.Map.CenterOnPosition(playerIndices);
    if (((Control) this.Canvas).Visible)
      this.Canvas.CenterOnPosition(playerIndices);
    this._lastPlayerPosition = new Vector2i?(playerIndices);
  }

  private void SetLabelState(TacticalMapControl.LabelMode newState, bool saveToConfig = false)
  {
    this._currentLabelState = newState;
    if (newState != TacticalMapControl.LabelMode.None)
      this._lastActiveState = newState;
    this.Map.CurrentLabelMode = newState;
    this.Canvas.CurrentLabelMode = newState;
    this.UpdateLabelsButtonAppearance();
  }

  private void UpdateLabelsButtonAppearance()
  {
    string str;
    Color color;
    switch (this._currentLabelState)
    {
      case TacticalMapControl.LabelMode.None:
        str = Loc.GetString("ui-tactical-map-labels-mode-none");
        color = Color.Red;
        break;
      case TacticalMapControl.LabelMode.Tactical:
        str = Loc.GetString("ui-tactical-map-labels-mode-tactical");
        color = Color.Green;
        break;
      case TacticalMapControl.LabelMode.Area:
        str = Loc.GetString("ui-tactical-map-labels-mode-area");
        color = Color.Orange;
        break;
      default:
        str = Loc.GetString("ui-tactical-map-labels-mode-none");
        color = Color.White;
        break;
    }
    if (this.LabelsButton != null)
    {
      this.LabelsButton.Text = str;
      ((Control) this.LabelsButton).Modulate = color;
    }
    if (this.LabelsButtonCanvas == null)
      return;
    this.LabelsButtonCanvas.Text = str;
    ((Control) this.LabelsButtonCanvas).Modulate = color;
  }

  private void UpdateSettingsVisibility()
  {
    ((Control) this.SettingsContainer).Visible = this._settingsVisible;
    this.SettingsToggleButton.Text = this._settingsVisible ? Loc.GetString("ui-tactical-map-settings-toggle-expanded") : Loc.GetString("ui-tactical-map-settings-toggle-collapsed");
  }

  private void UpdateFollowButtonText()
  {
    string str = this._followingPlayer ? Loc.GetString("ui-tactical-map-follow-player-active") : Loc.GetString("ui-tactical-map-follow-player-inactive");
    Color color = this._followingPlayer ? Color.Red : Color.White;
    if (this.FollowPlayerButton != null)
    {
      this.FollowPlayerButton.Text = str;
      ((Control) this.FollowPlayerButton).Modulate = color;
    }
    if (this.FollowPlayerButtonCanvas == null)
      return;
    this.FollowPlayerButtonCanvas.Text = str;
    ((Control) this.FollowPlayerButtonCanvas).Modulate = color;
  }

  private void UpdatePlayerFollowing(float deltaSeconds)
  {
    if (!this._followingPlayer)
      return;
    this._followUpdateTimer += deltaSeconds;
    if ((double) this._followUpdateTimer < 0.5)
      return;
    this._followUpdateTimer = 0.0f;
    Vector2i playerIndices;
    if (!this.TryFindPlayerBlip(out playerIndices))
      return;
    Vector2i? lastPlayerPosition = this._lastPlayerPosition;
    Vector2i vector2i = playerIndices;
    if ((lastPlayerPosition.HasValue ? (Vector2i.op_Inequality(lastPlayerPosition.GetValueOrDefault(), vector2i) ? 1 : 0) : 1) == 0)
      return;
    this.Map.CenterOnPosition(playerIndices);
    if (((Control) this.Canvas).Visible)
      this.Canvas.CenterOnPosition(playerIndices);
    this._lastPlayerPosition = new Vector2i?(playerIndices);
  }

  private void UpdateCooldownBar()
  {
    IGameTiming igameTiming = IoCManager.Resolve<IGameTiming>();
    TimeSpan timeSpan = this.NextUpdateAt - igameTiming.CurTime;
    if (timeSpan < TimeSpan.Zero)
    {
      ((BaseButton) this.UpdateCanvasButton).Disabled = false;
      ((Control) this.CooldownBar).Visible = false;
    }
    else
    {
      ((BaseButton) this.UpdateCanvasButton).Disabled = true;
      ((Control) this.CooldownBar).Visible = true;
      ((Range) this.CooldownBar).MinValue = (float) this.LastUpdateAt.TotalSeconds;
      ((Range) this.CooldownBar).MaxValue = (float) this.NextUpdateAt.TotalSeconds;
      ((Range) this.CooldownBar).Value = (float) (this.LastUpdateAt.TotalSeconds + this.NextUpdateAt.TotalSeconds - igameTiming.CurTime.TotalSeconds);
      this.CooldownLabel.Text = Loc.GetString("ui-tactical-map-cooldown-seconds", new (string, object)[1]
      {
        ("seconds", (object) (int) timeSpan.TotalSeconds)
      });
    }
  }

  private bool IsInQueenEyeMode()
  {
    IEntityManager ientityManager = IoCManager.Resolve<IEntityManager>();
    EntityUid? localEntity = ((ISharedPlayerManager) this._player).LocalEntity;
    QueenEyeActionComponent eyeActionComponent;
    return localEntity.HasValue && ientityManager.TryGetComponent<QueenEyeActionComponent>(localEntity.Value, ref eyeActionComponent) && eyeActionComponent.Eye.HasValue;
  }

  private void InvalidatePlayerCache()
  {
    this._cachedPlayerEntity = new EntityUid?();
    this._cachedPlayerNetId = new int?();
    this._cachedUserComponent = (TacticalMapUserComponent) null;
  }

  private bool TryGetCachedPlayerData(
    out int playerNetId,
    out TacticalMapUserComponent userComponent)
  {
    playerNetId = 0;
    userComponent = (TacticalMapUserComponent) null;
    EntityUid? localEntity = ((ISharedPlayerManager) this._player).LocalEntity;
    if (!localEntity.HasValue)
    {
      this.InvalidatePlayerCache();
      return false;
    }
    EntityUid? cachedPlayerEntity = this._cachedPlayerEntity;
    EntityUid? nullable = localEntity;
    if ((cachedPlayerEntity.HasValue == nullable.HasValue ? (cachedPlayerEntity.HasValue ? (EntityUid.op_Inequality(cachedPlayerEntity.GetValueOrDefault(), nullable.GetValueOrDefault()) ? 1 : 0) : 0) : 1) != 0)
    {
      IEntityManager ientityManager = IoCManager.Resolve<IEntityManager>();
      TacticalMapUserComponent mapUserComponent;
      if (!ientityManager.TryGetComponent<TacticalMapUserComponent>(localEntity.Value, ref mapUserComponent))
      {
        this.InvalidatePlayerCache();
        return false;
      }
      this._cachedPlayerEntity = localEntity;
      this._cachedPlayerNetId = new int?(NetEntity.op_Explicit(ientityManager.GetNetEntity(localEntity.Value, (MetaDataComponent) null)));
      this._cachedUserComponent = mapUserComponent;
    }
    if (!this._cachedPlayerNetId.HasValue || this._cachedUserComponent == null)
      return false;
    playerNetId = this._cachedPlayerNetId.Value;
    userComponent = this._cachedUserComponent;
    return true;
  }

  private bool TryFindPlayerBlip(out Vector2i playerIndices)
  {
    playerIndices = new Vector2i();
    int playerNetId;
    TacticalMapUserComponent userComponent;
    if (!this.TryGetCachedPlayerData(out playerNetId, out userComponent))
      return false;
    foreach ((int key, TacticalMapBlip tacticalMapBlip3) in userComponent.XenoBlips)
    {
      int num1 = key;
      TacticalMapBlip tacticalMapBlip2 = tacticalMapBlip3;
      int num2 = playerNetId;
      if (num1 == num2)
      {
        playerIndices = tacticalMapBlip2.Indices;
        return true;
      }
    }
    foreach ((key, tacticalMapBlip3) in userComponent.MarineBlips)
    {
      int num3 = key;
      TacticalMapBlip tacticalMapBlip4 = tacticalMapBlip3;
      int num4 = playerNetId;
      if (num3 == num4)
      {
        playerIndices = tacticalMapBlip4.Indices;
        return true;
      }
    }
    return false;
  }

